import pytest
import requests

BASE_URL = "http://localhost:8080/fhir"

def test_create_medication_request_valid_prescriber_non_controlled(prescriber_token, patient_id):
    payload = {
        "resourceType": "MedicationRequest",
        "status": "active",
        "intent": "order",
        "subject": {"reference": f"Patient/{patient_id}"},
        "medicationCodeableConcept": {
            "coding": [{"system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                         "code": "1049502", "display": "Amoxicillin 500mg"}]
        },
        "requester": {"reference": "Practitioner/prescriber-001"}
    }
    headers = {"Authorization": f"Bearer {prescriber_token}",
               "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{BASE_URL}/MedicationRequest", json=payload, headers=headers)
    assert resp.status_code == 201
    body = resp.json()
    assert body.get("resourceType") == "MedicationRequest"
    assert "id" in body
    assert body.get("status") == "active"

import requests

BASE_URL = "http://localhost:8080/fhir"

def test_create_medication_request_exactly_minimum_mandatory_fields(prescriber_token, patient_id):
    payload = {
        "resourceType": "MedicationRequest",
        "status": "draft",
        "intent": "proposal",
        "subject": {"reference": f"Patient/{patient_id}"},
        "medicationCodeableConcept": {
            "coding": [{"system": "http://www.nlm.nih.gov/research/umls/rxnorm",
                         "code": "1049502"}]
        }
    }
    headers = {"Authorization": f"Bearer {prescriber_token}",
               "Content-Type": "application/fhir+json"}
    resp = requests.post(f"{BASE_URL}/MedicationRequest", json=payload, headers=headers)
    assert resp.status_code == 201
    body = resp.json()
    assert body.get("resourceType") == "MedicationRequest"
    assert "id" in body and body["id"]
